// Products.js
import React, { useEffect, useState } from 'react';
import ProductForm from '../components/ProductForm';
import ProductList from '../components/ProductList';
import StockMovementForm from '../components/StockMovementForm';
import axios from 'axios';

const Products = () => {
    const [products, setProducts] = useState([]);
    const [movements, setMovements] = useState([]);
    const [productNames, setProductNames] = useState({});
    const [selectedProduct, setSelectedProduct] = useState(null); // Adicione esta linha

    const fetchProducts = async () => {
        try {
            const response = await axios.get('http://127.0.0.1:8000/api/produtos/');
            console.log(response.data); // Adicione esta linha para verificar os produtos
            setProducts(response.data);

            const namesMapping = response.data.reduce((acc, product) => {
                acc[product.id] = product.nome;
                return acc;
            }, {});
            setProductNames(namesMapping);
        } catch (error) {
            console.error("Erro ao buscar produtos:", error);
        }
    };

    // ... restante do código ...

    return (
        <div>
            <h2>Lista de Produtos</h2>
            <ProductForm refreshProducts={fetchProducts} selectedProduct={selectedProduct} setSelectedProduct={setSelectedProduct} />
            <ProductList products={products} onEdit={setSelectedProduct} />
            <h2>Registrar Movimentação de Estoque</h2>
            <StockMovementForm refreshMovements={fetchMovements} updateProductQuantity={updateProductQuantity} />
            {/* ... restante do código ... */}
        </div>
    );
};

export default Products;
